_NULL_SHA = "0" * 40  # blame's sha for lines not committed yet


def _git(repo_root: Path, *args: str) -> str:
    return subprocess.run(
        ["git", "-C", str(repo_root), *args],
        capture_output=True, text=True, check=True, timeout=60,
