    path-segment boundary — 'foo/bar.py' must never match 'ar.py'."""
    a = path_a.replace("\\", "/").rstrip("/")
    b = path_b.replace("\\", "/").rstrip("/")
    return a == b or a.endswith("/" + b) or b.endswith("/" + a)

