@router.post("/jobs")
def create_shrink_job(req: ShrinkRequest):
    """Enqueue an async shrink. The worker runs the REAL engine (plan → materialize →
    tree-equality verify) on a repo path it can reach; cloning from a GitHub URL is the
    GitHub-App milestone. For a local repo, the gitly CLI does the same flow inline."""
    job_id = uuid.uuid4().hex
    try:
        from workers.tasks.shrink import run_shrink

        run_shrink.delay(job_id, req.model_dump())
        queued = True
    except Exception:
        queued = False            # broker offline in local dev — degrade gracefully
    return {"job_id": job_id, "queued": queued}

def _parse_gh_pr_list(payload: str) -> tuple[list[int], set[str]]:
    """(APPROVED merged-PR numbers, human approver logins) from
    `gh pr list --json number,reviewDecision,latestReviews` output. Commits are fetched
    per-PR afterwards — asking for them in the list query blows GitHub's GraphQL node budget."""
    numbers: list[int] = []
    approvers: set[str] = set()
    for pr in json.loads(payload or "[]"):
        if pr.get("reviewDecision") != "APPROVED":
            continue
        if isinstance(pr.get("number"), int):
            numbers.append(pr["number"])
        for rv in pr.get("latestReviews") or []:
            login = ((rv.get("author") or {}).get("login") or "").strip()
            if rv.get("state") == "APPROVED" and login and "bot" not in login.lower():
                approvers.add(login)
    return numbers, approvers
